require(['app'], function(app){
app.views.footer=Backbone.View.extend({
    initialize:function(){
        console.log("initializing footer view");
    },
    render:function(){
        $(this.el).html(this.template());
        var timeVer ='20230114183327';
    /*    $.getJSON( "../json/version.json", function( data ) {

    console.log('test-'+data); //json output 
});*/
       // console.log(app.const.version.responseText); //json output 
        this.$("#version").text( app.const.version.responseText);
        return this},
    destroy_view:function(){
        this.undelegateEvents();
        $(this.el).removeData().unbind();
        this.remove();
        Backbone.View.prototype.remove.call(this);
    app.global.footerView=null}
});
return app.views.footer;
})